import requests
import json

class RabbitMQConfig:
    def __init__(self, host='localhost', port=15672, username='guest', password='guest'):
        self.host = host
        self.port = port
        self.username = username
        self.password = password
        self.base_url = f"http://{self.host}:{self.port}/api"
        
    def create_vhost(self, vhost_name):
        """Create a virtual host"""
        url = f"{self.base_url}/vhosts/{vhost_name}"
        response = requests.put(
            url,
            auth=(self.username, self.password),
            headers={'Content-Type': 'application/json'}
        )
        if response.status_code == 201:
            print(f"Created vhost: {vhost_name}")
        else:
            print(f"Failed to create vhost {vhost_name}: {response.status_code}")
            
    def delete_vhost(self, vhost_name):
        """Delete a virtual host"""
        url = f"{self.base_url}/vhosts/{vhost_name}"
        response = requests.delete(
            url,
            auth=(self.username, self.password)
        )
        if response.status_code == 204:
            print(f"Deleted vhost: {vhost_name}")
        else:
            print(f"Failed to delete vhost {vhost_name}: {response.status_code}")
            
    def create_user(self, username, password, tags=""):
        """Create a user"""
        url = f"{self.base_url}/users/{username}"
        payload = {
            "password": password,
            "tags": tags
        }
        response = requests.put(
            url,
            auth=(self.username, self.password),
            headers={'Content-Type': 'application/json'},
            data=json.dumps(payload)
        )
        if response.status_code == 201:
            print(f"Created user: {username}")
        else:
            print(f"Failed to create user {username}: {response.status_code}")
            
    def delete_user(self, username):
        """Delete a user"""
        url = f"{self.base_url}/users/{username}"
        response = requests.delete(
            url,
            auth=(self.username, self.password)
        )
        if response.status_code == 204:
            print(f"Deleted user: {username}")
        else:
            print(f"Failed to delete user {username}: {response.status_code}")
            
    def set_permissions(self, username, vhost_name, configure=".*", write=".*", read=".*"):
        """Set permissions for a user on a vhost"""
        url = f"{self.base_url}/permissions/{vhost_name}/{username}"
        payload = {
            "configure": configure,
            "write": write,
            "read": read
        }
        response = requests.put(
            url,
            auth=(self.username, self.password),
            headers={'Content-Type': 'application/json'},
            data=json.dumps(payload)
        )
        if response.status_code == 204:
            print(f"Set permissions for user {username} on vhost {vhost_name}")
        else:
            print(f"Failed to set permissions for user {username} on vhost {vhost_name}: {response.status_code}")

# Example usage
if __name__ == "__main__":
    # Initialize RabbitMQ configuration
    rmq = RabbitMQConfig()
    
    # Define applications and their configurations
    applications = [
        {
            "name": "app1",
            "vhost": "/app1",
            "user": "app1_user",
            "password": "app1_password"
        },
        {
            "name": "app2", 
            "vhost": "/app2",
            "user": "app2_user",
            "password": "app2_password"
        }
    ]
    
    # Create vhosts and users for each application
    for app in applications:
        # Create vhost
        rmq.create_vhost(app["vhost"])
        
        # Create user
        rmq.create_user(app["user"], app["password"])
        
        # Set permissions for the user on the vhost
        rmq.set_permissions(app["user"], app["vhost"])